const item = $input.first();
const inp = item.json || {};
const b = inp.body || inp;

function pick() {
  for (let i = 0; i < arguments.length; i++) {
    const k = arguments[i];
    if (b[k] !== undefined && b[k] !== null && b[k] !== '') return b[k];
  }
  return '';
}
function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

// Single business -> one fixed Evri claim ceiling (the cap submitted to Evri).
// Client credit = min(cost_value, CEILING); parcel_value submitted = CEILING.
const CEILING = 25;

// Map the n8n Form fields (keys are the field labels) to normalized slugs.
const email = String(pick('customer email address', 'email')).trim().toLowerCase();
let name = String(pick('name', 'customer_name', 'full name')).trim();
if (!name && email) name = email.split('@')[0];
const phone = String(pick('phone number', 'phone', 'phone_number')).trim();
const order_number = String(pick('Order Number', 'order_number')).trim();
const courier = String(pick('Courier', 'courier') || 'Evri').trim();
const claim_raw = String(pick('Claim for Loss or Damage', 'claim_type') || 'Lost');
const claim_type = /damage/i.test(claim_raw) ? 'Damage' : 'Lost'; // form 'Loss' -> Attio 'Lost'
const parcel_count = Number(pick('Number of Parcel Claim', 'parcel_count') || 1);
const tracking_number = String(pick('Tracking Number 1', 'tracking_number')).trim();
const additional_tracking = String(pick('More Tracking Number if any', 'additional_tracking')).trim();
const delivery_postcode = String(pick('Delivery Destination Postcode', 'delivery_postcode', 'postcode')).trim();
const customer_comment = String(pick('What is the reason for your claim?', 'customer_comment', 'comment')).trim();
const cost_value = Number(pick('Cost Value', 'cost_value') || 0);
const parcel_value = CEILING;

const out = { json: {
  correlation_id: uuidv4(),
  email, name, phone,
  courier, claim_type,
  tracking_number, additional_tracking, order_number,
  delivery_postcode, parcel_count, cost_value, parcel_value,
  customer_comment
} };

// Normalize whatever file the form uploaded to binary 'data' for the photo node.
const inb = item.binary || {};
const bk = Object.keys(inb)[0];
if (bk) out.binary = { data: inb[bk] };
return [out];

const g = $('Generate correlation_id').item.json;
let jsonData = $json ?? {};
const recId = $('Create Claim').item.json?.data?.id?.record_id ?? '';
const fileId = jsonData.data?.id?.file_id ?? jsonData.data?.file_id ?? jsonData.data?.id ?? '';
const fileUrl = jsonData.data?.url ?? jsonData.data?.download_url ?? jsonData.data?.values?.url ?? '';
const photo_url = fileUrl || (fileId ? ('attio-file:' + fileId) : '');
const claim = {
  correlation_id: g.correlation_id, order_number: g.order_number, courier: g.courier,
  claim_type: g.claim_type, parcel_value: g.parcel_value, cost_value: g.cost_value,
  delivery_postcode: g.delivery_postcode, tracking_number: g.tracking_number,
  additional_tracking: g.additional_tracking, customer_name: g.name, customer_email: g.email,
  customer_comment: g.customer_comment, photo_url, attio_claim_record_id: recId,
};
const nowIso = new Date().toISOString();
const doc = { ...claim, state:'VALIDATING', created_at:nowIso, updated_at:nowIso, verdict:null, decision:null, attio_status:null, error:null, human_review:null };
function toFV(v){ if(v===null||v===undefined)return{nullValue:null}; if(typeof v==='boolean')return{booleanValue:v}; if(typeof v==='number')return Number.isInteger(v)?{integerValue:String(v)}:{doubleValue:v}; if(typeof v==='string')return{stringValue:v}; if(Array.isArray(v))return{arrayValue:{values:v.map(toFV)}}; if(typeof v==='object')return{mapValue:{fields:toFF(v)}}; return{stringValue:String(v)}; }
function toFF(o){ const fields={}; for(const [k,val] of Object.entries(o)) fields[k]=toFV(val); return fields; }
return { json: { claim, doc, firestoreFields: toFF(doc) } };

const b = $input.first().json;
function pick(){for(let i=0;i<arguments.length;i++){const k=arguments[i];if(b[k]!==undefined&&b[k]!==null&&b[k]!=='')return b[k];}return '';}
const barcode = String(pick('Tracking / Barcode','barcode','tracking_number')).trim();
const claim_status = String(pick('Evri outcome code','claim_status')).trim();
const settle = pick('Settlement amount','settlement_amount');
const out = { barcode, claim_status };
if (settle !== '' && settle !== undefined && settle !== null) out.settlement_amount = Number(settle);
return [{ json: out }];

const g = $('Generate correlation_id').first();
const src = $('Build VALIDATING doc').item.json;
const bin = (g.binary && g.binary.data) ? { data: g.binary.data } : {};
return { json: { claim: src.claim, claimJson: JSON.stringify(src.claim, null, 2) }, binary: bin };

const geminiResponse = $json.output ?? $json;
const prevDoc = $('Build VALIDATING doc').item.json.doc;
const claim = $('Build VALIDATING doc').item.json.claim;
const VERDICT_LABELS=['GENUINE','INCONSISTENT','INSUFFICIENT_EVIDENCE','SUSPECTED_FRAUD'];
const CLAIM_TYPES=['DAMAGE','LOSS','SHORTAGE','NON_DELIVERY'];
const SEVERITIES=['NONE','MINOR','MODERATE','SEVERE','TOTAL'];
const ACTIONS=['AUTO_PROCEED','ESCALATE_HUMAN','REJECT'];
const isRec=(v)=>typeof v==='object'&&v!==null&&!Array.isArray(v);
const clamp01=(n)=>{const x=(typeof n==='number'&&isFinite(n))?n:0;return Math.max(0,Math.min(1,x));};
const asEnum=(v,a,fb)=>(typeof v==='string'&&a.includes(v))?v:fb;
const asArr=(v)=>Array.isArray(v)?v.filter((x)=>typeof x==='string'):[];
const asStr=(v,fb='')=>typeof v==='string'?v:fb;
const asBool=(v,fb=false)=>typeof v==='boolean'?v:fb;
const asInt=(v,fb=0)=>(typeof v==='number'&&isFinite(v))?Math.trunc(v):fb;
function asObject(input){ if(isRec(input))return input; if(typeof input==='string'){ let t=input.trim(); const m=/^```(?:json)?\s*([\s\S]*?)\s*```$/i.exec(t); if(m)t=m[1].trim(); return JSON.parse(t);} throw new Error('parseVerdict: input must be object or JSON string'); }
function unwrap(obj){ if(!('candidates' in obj))return obj; const cands=obj.candidates; if(!Array.isArray(cands)||cands.length===0)throw new Error('parseVerdict: no candidates'); const first=cands[0]; const parts=first?.content?.parts; if(!Array.isArray(parts)||parts.length===0)throw new Error('parseVerdict: no content parts'); const text=parts.map((p)=>(p&&typeof p.text==='string')?p.text:'').join('').trim(); if(!text)throw new Error('parseVerdict: empty text'); return asObject(text); }
function parseVerdict(resp){ if(resp===null||resp===undefined)throw new Error('parseVerdict: null input'); const raw=unwrap(asObject(resp)); if(typeof raw.verdict!=='string'||!VERDICT_LABELS.includes(raw.verdict))throw new Error('parseVerdict: missing/invalid verdict field'); const da=isRec(raw.damage_assessment)?raw.damage_assessment:{}; const cc=isRec(raw.cross_checks)?raw.cross_checks:{}; const au=isRec(raw.authenticity)?raw.authenticity:{}; return { verdict:raw.verdict, confidence:clamp01(raw.confidence), claim_type:asEnum(raw.claim_type,CLAIM_TYPES,'DAMAGE'), damage_assessment:{severity:asEnum(da.severity,SEVERITIES,'NONE'),damage_types:asArr(da.damage_types),affected_units:asInt(da.affected_units,0)}, cross_checks:{matches_comment:asBool(cc.matches_comment),photo_shows_claimed_damage:asBool(cc.photo_shows_claimed_damage),sku_or_label_legible:asBool(cc.sku_or_label_legible)}, authenticity:{looks_screenshot_or_reused:asBool(au.looks_screenshot_or_reused),notes:asStr(au.notes)}, inconsistencies:asArr(raw.inconsistencies), acceptance_likelihood:clamp01(raw.acceptance_likelihood), recommended_action:asEnum(raw.recommended_action,ACTIONS,'ESCALATE_HUMAN'), rationale:asStr(raw.rationale), evidence_citations:asArr(raw.evidence_citations) }; }
const PROCEED_CONFIDENCE=0.85, DEFAULT_HIGH_VALUE_THRESHOLD=100;
const gates={ within_window:true, claimant_ok:true, value_within_ceiling:true, photo_present:!!claim.photo_url };
function fuseDecision(verdict,gates,opts){ opts=opts||{}; const allPass=gates.within_window&&gates.claimant_ok&&gates.value_within_ceiling; if(!allPass)return{decision:'AUTO_REJECT',attio_status:'Rejected'}; const hv=(typeof opts.highValueThreshold==='number')?opts.highValueThreshold:DEFAULT_HIGH_VALUE_THRESHOLD; const isHigh=(typeof opts.parcelValue==='number')&&opts.parcelValue>hv; const authFlag=verdict.authenticity&&verdict.authenticity.looks_screenshot_or_reused===true; const conf=(typeof verdict.confidence==='number')?verdict.confidence:0; const canProceed=verdict.verdict==='GENUINE'&&conf>=PROCEED_CONFIDENCE&&!authFlag&&!isHigh; if(canProceed)return{decision:'AUTO_PROCEED',attio_status:'Raised'}; return{decision:'ESCALATE_HUMAN',attio_status:'OnHold'}; }
function toFV(v){ if(v===null||v===undefined)return{nullValue:null}; if(typeof v==='boolean')return{booleanValue:v}; if(typeof v==='number')return Number.isInteger(v)?{integerValue:String(v)}:{doubleValue:v}; if(typeof v==='string')return{stringValue:v}; if(Array.isArray(v))return{arrayValue:{values:v.map(toFV)}}; if(typeof v==='object')return{mapValue:{fields:toFF(v)}}; return{stringValue:String(v)}; }
function toFF(o){ const fields={}; for(const [k,val] of Object.entries(o)) fields[k]=toFV(val); return fields; }
const nowIso=new Date().toISOString();
let verdict, decision, errorMessage=null;
try { verdict=parseVerdict(geminiResponse); decision=fuseDecision(verdict,gates,{parcelValue:claim.parcel_value}); }
catch(e){ errorMessage='Gemini/parse failure: '+(e&&e.message?e.message:String(e)); }
if (errorMessage) {
  const errDoc={ ...prevDoc, state:'ERROR', updated_at:nowIso, verdict:null, decision:null, attio_status:null, error:errorMessage, human_review:prevDoc.human_review??null };
  return { json: { ok:false, error:errorMessage, doc:errDoc, firestoreFields:toFF(errDoc), correlation_id:claim.correlation_id } };
}
const doc={ ...prevDoc, state:'VALIDATED', updated_at:nowIso, verdict, decision:decision.decision, attio_status:decision.attio_status, error:null, human_review:prevDoc.human_review??null };
return { json: { ok:true, verdict, decision, attio_status:decision.attio_status, attio_claim_record_id:claim.attio_claim_record_id, correlation_id:claim.correlation_id, doc, firestoreFields:toFF(doc), attioStatusBody:{ data:{ values:{ status:decision.attio_status } } } } };

const src = $('Build VALIDATING doc').item.json;
const prevDoc = src ? src.doc : null;
const nowIso = new Date().toISOString();
const errMsg = ($json && $json.error && ($json.error.message || $json.error)) ? String($json.error.message || $json.error)
  : (($json && $json.message) ? String($json.message) : 'Validation step failed (see n8n execution log).');
const base = prevDoc || { correlation_id: src?.claim?.correlation_id ?? 'unknown', state:'VALIDATING', created_at:nowIso, updated_at:nowIso, verdict:null, decision:null, attio_status:null, error:null, human_review:null };
const doc = { ...base, state:'ERROR', updated_at:nowIso, verdict:null, decision:null, attio_status:null, error:errMsg, human_review:base.human_review??null };
function toFV(v){ if(v===null||v===undefined)return{nullValue:null}; if(typeof v==='boolean')return{booleanValue:v}; if(typeof v==='number')return Number.isInteger(v)?{integerValue:String(v)}:{doubleValue:v}; if(typeof v==='string')return{stringValue:v}; if(Array.isArray(v))return{arrayValue:{values:v.map(toFV)}}; if(typeof v==='object')return{mapValue:{fields:toFF(v)}}; return{stringValue:String(v)}; }
function toFF(o){ const fields={}; for(const [k,val] of Object.entries(o)) fields[k]=toFV(val); return fields; }
return { json: { doc, firestoreFields: toFF(doc), correlation_id: base.correlation_id } };

// Final node: surface the AI Agent's verdict + the fused decision so the
// agent output is visible in the execution panel (and the n8n logs).
const fuse = $('Fuse + decide').item.json;
let agentOutput = null;
try { const a = $('AI Agent: validate claim').item.json; agentOutput = a.output ?? a; } catch (e) {}
const summary = {
  correlation_id: fuse.correlation_id,
  decision: fuse.decision,
  attio_status: fuse.attio_status,
  verdict: fuse.verdict,
  agent_output: agentOutput,
};
console.log('=== AGENT VERDICT ===\n' + JSON.stringify(summary, null, 2));
return { json: summary };
